class Solution:
    def sortVowels(self, s: str) -> str:
        vowels = 'aeiouAEIOU'
        # Extract vowels and sort them using Timsort (O(n log n))
        sorted_vowels = sorted([c for c in s if c in vowels])

        # Build the result string
        result = []
        vowel_index = 0
        for c in s:
            if c in vowels:
                result.append(sorted_vowels[vowel_index])
                vowel_index += 1
            else:
                result.append(c)

        return ''.join(result)
